  async create(payload: CreatePriceSettingInput) {
    const room = await this.roomRepo.findById(payload.roomId);
    if (!room) throw new NotFoundError(ErrorCode.ROOM_NOT_FOUND);

    const hotel = await this.hotelRepo.findById(payload.hotelId);
    if (!hotel) throw new NotFoundError(ErrorCode.HOTEL_NOT_FOUND);

    const countries = await this.countryRepo.find({
      where: { id: In(payload.countries) },
    });
    if (!countries) throw new BusinessLogicError(ErrorCode.COUNTRY_NOT_FOUND);

    const entity = new PriceSetting();
    entity.mealPlan = payload.mealPlan;
    entity.price = payload.price;
    entity.countries = countries;
    entity.condition = payload.condition;
    entity.source = payload.source || 'BGT';
    entity.room = room;
    entity.hotel = hotel;
    entity.ownerId = payload.ownerId;
    entity.createdBy = payload.createdBy;
    entity.dayType = payload.dayType;
    entity.name = this.getNameRatePlan(
      payload.condition,
      payload.mealPlan,
      room?.localName,
      payload.amount,
      payload.unitType,
    );

    if (payload.condition === CancellationType.NO_CANCELLATION) {
      entity.cancellationPeriod = null;
    } else {
      entity.cancellationPeriod = payload.cancellationPeriod;
      entity.cancellationPeriodUnitTime = payload.cancellationPeriodUnitTime;
    }

    if (payload.condition === CancellationType.CANCELLATION_CHARGE) {
      entity.unitType = payload.unitType;
      entity.amount = payload.amount;
    }

    if (payload.seasonIds?.length > 0) {
      const seasons = await this.seasonRepo.find({ where: { id: In(payload.seasonIds) } });
      if (!seasons.length) throw new NotFoundError(ErrorCode.SEASON_NOT_FOUND);

      const countryIds = countries?.map(c => c.id).sort((a, b) => a - b);

      // Check duplicate cho từng season
      for (const season of seasons) {
        this.validatePeriodsFormat(season.periods);
        await this.checkDuplicate(
          entity.hotel.id,
          entity.room.id,
          entity.mealPlan,
          countryIds,
          entity.dayType,
          entity.condition,
          season.id,
          season.periods,
        );
      }

      const entities = seasons.map(season => {
        const cloned = new PriceSetting();
        Object.assign(cloned, entity);
        cloned.season = season;
        cloned.periods = season.periods;
        return cloned;
      });
      const savedPriceSettings = await this.repo.saveMany(entities);
      await Promise.all(savedPriceSettings.map(ps => this.syncRateCalendar(ps)));
      return savedPriceSettings;
    } else {
      entity.periods = payload.periods;
    }

    this.validatePeriodsFormat(entity.periods);
    const countryIds = countries?.map(c => c.id).sort((a, b) => a - b);
    await this.checkDuplicate(
      entity.hotel.id,
      entity.room.id,
      entity.mealPlan,
      countryIds,
      entity.dayType,
      entity.condition,
      null,
      entity.periods,
    );

    const savedPriceSetting = await this.repo.save(entity);
    await this.syncRateCalendar(savedPriceSetting);
    return savedPriceSetting;
  }

  async findAll(query: PriceSettingQueryParamInput) {
    return this.repo.findAll(query);
