  async checkValidCreOrUpd(hotelId: number, roomIds: number[]) {
    const rs = await this.repo.find({
      where: { hotel: { id: hotelId }, room: { id: In(roomIds) } },
      relations: ['hotel', 'room'],
    });
    const rooms = new Set(rs.map(r => r.room.id));
    if (rooms.size !== roomIds.length) {
      // tìm room Ids chưa có price setting
      const existingRoomIds = rs.map(r => r.room.id);
      const missingRoomIds = roomIds.filter(id => !existingRoomIds.includes(id));
      throw new BusinessLogicError(
        ErrorCode.PRICE_SETTING_FIRST,
        `Missing price settings for room IDs: ${missingRoomIds.join(', ')}`,
      );
    }
  }

