import { CreateSeasonInput, SeasonQueryParamsInput, UpdateSeasonInput } from '@Services/types/SeasonInput';

import { CreateEventDto } from '@Rests/types/SeasonDto';

@Service()
export class SeasonService {
  constructor(
    private readonly seasonRepo: SeasonRepository,
    private readonly seasonEventRepo: SeasonEventRepository,
    private readonly hotelRepo: HotelRepository,
  ) {}

  private async validateSeasonDates(
    periods: RangeDate[],
    seasonType: SeasonType,
    hotelId: number,
    ownerId: string,
    excludeId?: number,
  ) {
    if (!periods || !Array.isArray(periods) || periods.length === 0) {
      return;
    }

    for (const dateRange of periods) {
      if (!dateRange.startDate || !dateRange.endDate) {
        throw new BusinessLogicError(ErrorCode.SEASON_DATES_INVALID);
      }

      const startDate = dayjs(dateRange.startDate);
      const endDate = dayjs(dateRange.endDate);

      if (!startDate.isValid() || !endDate.isValid()) {
        throw new BusinessLogicError(ErrorCode.SEASON_DATES_INVALID);
      }

      if (startDate.isAfter(endDate)) {
        throw new BusinessLogicError(ErrorCode.SEASON_START_DATE_MUST_BE_BEFORE_END_DATE);
      }
    }

    const query = this.seasonRepo.createQueryBuilder('entity').where('entity.ownerId = :ownerId', { ownerId });

    if (excludeId) {
      query.andWhere('entity.id != :excludeId', { excludeId });
    }

    if (hotelId) {
      query.andWhere('entity.hotelId = :hotelId', { hotelId });
    }

    if (seasonType) {
      query.andWhere('entity.type = :seasonType', { seasonType });
    }

    const otherSeasons = await query.getMany();

    for (const otherSeason of otherSeasons) {
      const otherSeasonDates = otherSeason.periods;

      for (const newRange of periods) {
        const newStart = dayjs(newRange.startDate);
        const newEnd = dayjs(newRange.endDate);

        for (const otherRange of otherSeasonDates) {
          const otherStart = dayjs(otherRange.startDate);
          const otherEnd = dayjs(otherRange.endDate);

          if (newStart.isSameOrBefore(otherEnd) && newEnd.isSameOrAfter(otherStart)) {
            throw new BusinessLogicError(ErrorCode.PERIODS_OVERLAP);
          }
        }
      }
    }
  }

  private async assignSeasonDataByType(
    entity: Season,
    type: SeasonType,
    data: {
      season?: SeasonTag;
      day?: SeasonDay;
      eventId?: number;
      eventData?: CreateEventDto;
    },
    isCreate: boolean = false,
  ) {
    switch (type) {
      case SeasonType.SEASON:
        if (isCreate && !data.season) {
          throw new BusinessLogicError(ErrorCode.SEASON_TAG_REQUIRED);
        }
        if (!isCreate && data.season === undefined) {
          throw new BusinessLogicError(ErrorCode.SEASON_TAG_REQUIRED);
        }
        entity.season = data.season;
        entity.day = null;
        entity.event = null;
        break;

      case SeasonType.DAY:
        if (isCreate && !data.day) {
          throw new BusinessLogicError(ErrorCode.SEASON_DAY_REQUIRED);
        }
        if (!isCreate && data.day === undefined) {
          throw new BusinessLogicError(ErrorCode.SEASON_DAY_REQUIRED);
        }
        // check existing type day
        const exist = await this.seasonRepo
          .createQueryBuilder('season')
          .where('season.type = :type', { type: SeasonType.DAY })
          .andWhere('season.hotelId = :hotelId', { hotelId: entity.hotel.id })
          .andWhere(`season.day->>'name' = :dayName`, { dayName: data.day.name })
