  async completions(params: HotelSearchSuggestionQuery): Promise<HotelSearchSuggestionResponse> {
    const { q, limit = 10 } = params;
    const maxDestinations = Math.min(3, limit);
    const minScore = 0.001;
    const hotelWeight = 1.0;
    const destinationWeight = 0.9; // prefer hotels slightly

    const destinations = await this.destinationRepo.fullTextSearch(q, maxDestinations);
    const hotels = await this.hotelRepo.fullTextSearch(q, limit);

    const items: HotelSearchSuggestItem[] = [];

    destinations.forEach(d => {
      const score = (d as any).score ?? 0;
      if (score >= minScore) {
        items.push({
          type: 'DESTINATION',
          id: d.id,
          name: d.name,
          score: score * destinationWeight,
          subTitle: `${d.ward?.name || ''}${d.district?.name ? ', ' + d.city?.name : ''}`,
          totalHotels: Number((d as any).totalHotels) || 0,
        });
      }
    });

    hotels.forEach(h => {
      const score = (h as any).score ?? 0;
      if (score >= minScore) {
        items.push({
          type: 'HOTEL',
          id: h.id,
          name: h.localName || h.globalName || h.code,
          score: score * hotelWeight,
          subTitle: h.subTitle,
          totalRoom: Number((h as any).totalRooms) || 0,
        });
      }
    });

    items.sort((a, b) => b.score - a.score);

    const limited: HotelSearchSuggestItem[] = [];
    let destinationCount = 0;
    for (const item of items) {
      if (limited.length >= limit) break;
      if (item.type === 'DESTINATION') {
        if (destinationCount >= maxDestinations) continue;
        destinationCount += 1;
      }
      limited.push(item);
    }

    const response = new HotelSearchSuggestionResponse();
    response.suggestions = limited;
    // response.destinations = limited.filter(i => i.type === 'DESTINATION').map(i => i.destination!) as any;
    // response.hotels = limited.filter(i => i.type === 'HOTEL').map(i => i.hotel!) as any;
    return response;
  }

