  private async resolveHotelIds(destinationId?: number, hotelId?: number): Promise<number[]> {
    if (hotelId) {
      const hotel = await this.hotelRepo.findOne({ where: { id: hotelId, status: HotelStatus.ACTIVE } });
      return hotel ? [hotel.id] : [];
    }

    if (!destinationId) return [];
    const destination = await this.destinationRepo.findOne({ where: { id: destinationId } });
    if (!destination) return [];

    const mapped = await this.destinationRepo.findHotelIds(destination.id);
    if (mapped.length) return mapped;

    const qb = this.hotelRepo
      .createQueryBuilder('hotel')
      .select('hotel.id', 'id')
      .leftJoin('hotel.ward', 'ward')
      .leftJoin('ward.district', 'district')
      .leftJoin('district.city', 'city')
      .where('hotel.status = :status', { status: HotelStatus.ACTIVE });

    if (destination.cityId) qb.andWhere('city.id = :cityId', { cityId: destination.cityId });
    if (destination.districtId) qb.andWhere('district.id = :districtId', { districtId: destination.districtId });
    if (destination.wardId) qb.andWhere('ward.id = :wardId', { wardId: destination.wardId });

    const rows = await qb.getRawMany();
    return rows.map(row => Number(row.id));
  }

  private groupRatesByHotel(rows: AggregatedRateRow[]): Map<number, AggregatedRateRow[]> {
    const grouped = new Map<number, AggregatedRateRow[]>();
    rows.forEach(row => {
      const list = grouped.get(row.hotelId) || [];
      list.push(row);
      grouped.set(row.hotelId, list);
    });
    return grouped;
  }

  private getDayTypePriority(dayType?: DayType | null) {
    return dayType === DayType.WEEKEND ? 0 : 1;
  }

  private compareAggregatedRates(a: AggregatedRateRow, b: AggregatedRateRow) {
    const priorityDiff = this.getDayTypePriority(a.dayType) - this.getDayTypePriority(b.dayType);
    if (priorityDiff !== 0) return priorityDiff;
    return a.baseTotal - b.baseTotal;
  }

  private compareHotelPriceOptions(a: HotelPriceOption, b: HotelPriceOption) {
    const priorityDiff = this.getDayTypePriority(a.dayType) - this.getDayTypePriority(b.dayType);
    if (priorityDiff !== 0) return priorityDiff;
    return a.baseTotal - b.baseTotal;
  }

  private assignRooms(
    rateRows: AggregatedRateRow[],
    roomRequests: HotelSearchRoomDto[],
    roomMap: Map<number, HotelSearchRoomInfo>,
  ): HotelPriceRoomSelection[] | null {
    const requests = [...roomRequests].sort((a, b) => this.getGuestCount(b) - this.getGuestCount(a));
    const remaining = rateRows.map(r => ({ ...r }));
    const selection: HotelPriceRoomSelection[] = [];

    for (const request of requests) {
      const guests = this.getGuestCount(request);
      const candidate = remaining
        .filter(r => r.maxCapacity >= guests)
        .sort((a, b) => this.compareAggregatedRates(a, b));
      if (!candidate.length) return null;
      const chosen = candidate[0];
      const hasAllotment = chosen.minAllotment > 0;
      chosen.minAllotment = Math.max(chosen.minAllotment - 1, 0);
      selection.push({
        roomId: chosen.roomId,
        baseTotal: chosen.baseTotal,
        guestCount: guests,
        guestDetail: {
          adults: request.adults,
          children: request.children.length || 0,
        },
        hasAllotment,
        room: roomMap.get(chosen.roomId),
        priceSettingId: chosen.priceSettingId ?? undefined,
        mealPlan: chosen.mealPlan ?? undefined,
        source: chosen.source ?? undefined,
        condition: chosen.condition ?? undefined,
        cancellationPeriod: chosen.cancellationPeriod ?? undefined,
        cancellationPeriodUnitTime: chosen.cancellationPeriodUnitTime ?? undefined,
        unitType: chosen.unitType ?? undefined,
        amount: chosen.amount ?? undefined,
        dayType: chosen.dayType ?? undefined,
        stayDates: chosen.stayDates ?? undefined,
      });
    }
    return selection;
  }

  private buildRoomOptions(
    rateRows: AggregatedRateRow[],
    roomRequests: HotelSearchRoomDto[],
    roomMap: Map<number, HotelSearchRoomInfo>,
  ): HotelPriceOption[] {
    const options: HotelPriceOption[] = [];
    roomRequests.forEach(request => {
      const guests = this.getGuestCount(request);
      const candidates = rateRows
        .filter(r => r.maxCapacity >= guests)
        .sort((a, b) => this.compareAggregatedRates(a, b));
      candidates.forEach(c => {
        options.push({
          roomId: c.roomId,
          baseTotal: c.baseTotal,
          maxCapacity: c.maxCapacity,
          maxAdults: c.maxAdults,
          maxChildren: c.maxChildren,
          guestCount: guests,
          guestDetail: {
            adults: request.adults,
            children: request.children.length || 0,
          },
          hasAllotment: c.minAllotment > 0,
          room: roomMap.get(c.roomId),
          priceSettingId: c.priceSettingId ?? undefined,
          mealPlan: c.mealPlan ?? undefined,
          source: c.source ?? undefined,
          condition: c.condition ?? undefined,
          cancellationPeriod: c.cancellationPeriod ?? undefined,
          cancellationPeriodUnitTime: c.cancellationPeriodUnitTime ?? undefined,
          unitType: c.unitType ?? undefined,
          amount: c.amount ?? undefined,
          dayType: c.dayType ?? undefined,
          stayDates: c.stayDates ?? undefined,
        });
      });
    });
    return options;
  }

