  private normalizeRooms(rooms: HotelSearchRoomDto[]) {
    return [...rooms]
      .map(r => ({
        adults: r.adults,
        children: (r.children || []).map(c => c.age).sort(),
      }))
      .sort((a, b) => b.adults + b.children.length - (a.adults + a.children.length));
  }

  private buildSearchId(
    destinationId: number | undefined,
    hotelId: number | undefined,
    checkIn: dayjs.Dayjs,
    checkOut: dayjs.Dayjs,
    rooms: { adults: number; children: number[] }[],
  ) {
    const payload = {
      destinationId: destinationId || null,
      hotelId: hotelId || null,
      checkIn: checkIn.format('YYYY-MM-DD'),
      checkOut: checkOut.format('YYYY-MM-DD'),
      rooms,
    };
    const hash = createHash('sha1').update(JSON.stringify(payload)).digest('hex');
    return hash;
  }

  private sliceResults(items: HotelPriceSearchItem[], page: number, size: number) {
    const start = (page - 1) * size;
    const pagedItems = items.slice(start, start + size);
    const nextCursor = start + size < items.length ? start + size : undefined;
    return { items: pagedItems, nextCursor };
  }

  private async readCache(searchId: string): Promise<{ items: HotelPriceSearchItem[]; total: number } | null> {
    if (!this.cache) return null;
    const key = `hotel_search:${searchId}`;
    const cached = await this.cache.get(key);
    if (!cached) return null;
    try {
      return JSON.parse(cached);
    } catch {
      return null;
    }
  }

  private async writeCache(searchId: string, data: { items: HotelPriceSearchItem[]; total: number }) {
    if (!this.cache) return;
    const key = `hotel_search:${searchId}`;
    const ttlSeconds = 10;
    await this.cache.setex(key, ttlSeconds, JSON.stringify(data));
  }

  private buildResponse(
    items: HotelPriceSearchItem[],
    total: number,
    page: number,
    size: number,
    searchId: string,
    nextCursor?: number,
  ) {
    const resp = new HotelPriceSearchResponse()
      .withItems(items)
      .withTotal(total)
      .withPage(page)
      .withSize(size)
      .withSortBy('netTotal');
    resp.searchId = searchId;
    resp.nextCursor = nextCursor;
    return resp;
  }

  private findCheapestOption(options: HotelPriceOption[]): HotelPriceOption | undefined {
    if (!options.length) return undefined;
    return options.reduce((best, option) => (option.baseTotal < best.baseTotal ? option : best));
  }

  private applyPromotions(
    baseTotal: number,
    stayNights: number,
    promotions: RatePromotion[],
    selection: HotelPriceRoomSelection[],
  ) {
    if (!promotions.length) {
      return { discountTotal: 0, totalAfterPromo: baseTotal };
    }
    // take highest priority then highest discount
    const sorted = promotions.sort((a, b) => b.priority - a.priority);
    let bestDiscount = 0;
    sorted.forEach(promo => {
      const discount = this.calculateDiscount(baseTotal, stayNights, promo);
      if (discount > bestDiscount) bestDiscount = discount;
    });
    const totalAfterPromo = Math.max(0, baseTotal - bestDiscount);
    return { discountTotal: bestDiscount, totalAfterPromo };
  }

  private calculateDiscount(baseTotal: number, stayNights: number, promo: RatePromotion): number {
    switch (promo.promoType) {
      case RatePromotionType.PERCENT:
        return (baseTotal * Number(promo.value)) / 100;
      case RatePromotionType.FIXED:
        return Number(promo.value);
      case RatePromotionType.STAY_PAY: {
        const payNights = Math.max(1, Number(promo.value));
        const freeNights = Math.floor(stayNights / (payNights + 1));
        const avgNight = baseTotal / stayNights;
        return freeNights * avgNight;
      }
      default:
        return 0;
    }
  }

  private applyFees(
    amountAfterPromo: number,
    feeRules: FeeRule[],
    stayNights: number,
    roomRequests: HotelSearchRoomDto[],
  ): number {
    if (!feeRules.length) return 0;
    const totalGuests = roomRequests.reduce((acc, r) => acc + this.getGuestCount(r), 0);
    let totalFee = 0;

    feeRules.forEach(rule => {
      const value = Number(rule.value);
      const scopeMultiplier =
        rule.scope === FeeRuleScope.PER_NIGHT ? stayNights : rule.scope === FeeRuleScope.PER_GUEST ? totalGuests : 1;

      switch (rule.feeType) {
        case FeeRuleType.SERVICE_CHARGE:
        case FeeRuleType.TAX:
        case FeeRuleType.FIXED_FEE: {
          const fee = rule.method === FeeRuleMethod.PERCENT ? (amountAfterPromo * value) / 100 : value;
          totalFee += fee * scopeMultiplier;
          break;
        }
        case FeeRuleType.EXTRA_ADULT:
        case FeeRuleType.EXTRA_CHILD: {
          const count =
            rule.feeType === FeeRuleType.EXTRA_ADULT
              ? roomRequests.reduce((acc, r) => acc + r.adults, 0)
              : roomRequests.reduce((acc, r) => acc + (r.children?.length || 0), 0);
          const fee = rule.method === FeeRuleMethod.PERCENT ? (amountAfterPromo * value) / 100 : value;
          const extraMultiplier =
            rule.scope === FeeRuleScope.PER_NIGHT
              ? stayNights * count
              : rule.scope === FeeRuleScope.PER_GUEST
              ? count
              : count;
          totalFee += fee * extraMultiplier;
          break;
        }
        default:
          break;
      }
    });

    return totalFee;
  }

  private getGuestCount(room: HotelSearchRoomDto) {
    return (room.adults || 0) + (room.children?.length || 0);
  }
